const cliente = $input.item.json;
const cron = (cliente.config && cliente.config.apify && cliente.config.apify.cron_cadence_per_function) || {};
const tier = (cliente.config && cliente.config.apify && cliente.config.apify.plan_tier) || 'basic';
const scopeFunctions = ["instagram_scraper","facebook_ads_library_scraper","linkedin_company_scraper"];
const activas = scopeFunctions.filter(fn => cron[fn] != null);
return activas.map(fn => ({
  json: { client_id: cliente.id, client_name: cliente.name, apify_function: fn, cadence: cron[fn], tier }
}));

