parameters.jsCode:
const items = $input.all();
const summary = { total_calls: items.length, successes: 0, errors: 0, skipped_gate: 0, by_function: {} };
for (const it of items) {
  const r = it.json || {};
  const fn = r.apify_function || 'unknown';
  summary.by_function[fn] = (summary.by_function[fn] || 0) + 1;
  if (r.status === 'skipped' || r.skip_reason) summary.skipped_gate++;
  else if (r.success === false || r.error) summary.errors++;
  else summary.successes++;
}
return [{ json: { scope: 'onboarding_e2e', destination_table: 'client_competitive_landscape', summary, ran_at: new Date().toISOString() } }];
